- Implement a widget wrapper:
  ```rust
  #[cfg(feature = "egui")]
  pub fn mermaid_widget(ui: &mut egui::Ui, src: &str, theme: &Theme) {
      let available_size = ui.available_size();
      let (rect, painter) = ui.allocate_painter(available_size, egui::Sense::hover());
      let diagram = parse(src).and_then(|d| layout(&d, theme));
      if let Ok(scene) = diagram {
          let mut backend = EguiBackend { painter: &painter };
          backend.begin(scene.width, scene.height);
          for e in &scene.elements { backend.draw_element(e); }
          backend.end();
      } else {
          // optionally render error text
      }
  }
  ```
